const SetValue = async (context) => {
  // Check if final date is set - early return
  if (context?.Form?.InvoicePage?.IssueDate_Final?.Value !== "") {
    return "N/A";
  }

  // Check if invoice number is empty
  if (context?.Form?.InvoicePage?.InvoiceNumber_Final?.Value == "") {
    return "";
  }

  // Get the invoice details grid
  const grid = context?.Form?.InvoicePage?.InvoiceDetails || [];

  if (grid.length == 0) {
    return "Coordinator"; // Default start
  }

  // Get the most recent action (first row since sorted newest first)
  const mostRecentAction = grid[0];
  const recentApprover = mostRecentAction?.StatusBy?.Text || "";
  const recentStatus = mostRecentAction?.StatusFinal?.Value || "";

  // Define status and approver constants
  const stayStatuses = ["Received", "In Review"];
  const coordinators = ["Veronica Becerra", "Mayra Chavez"];

  // Check if status is Pending Corrections - always goes to contractor
  if (recentStatus == "Pending Corrections") {
    return context?.Form?.InvoicePage?.Contractor?.Text || "";
  }

  // Check if corrections were submitted - return to whoever requested them
  if (recentStatus == "Corrections Submitted") {
    // Find the previous action where someone sent it for corrections
    for (let i = 1; i < grid.length; i++) {
      if (grid[i]?.StatusFinal?.Value == "Pending Corrections") {
        return grid[i]?.StatusBy?.Text || "Coordinator";
      }
    }
    return "Coordinator"; // Fallback if no previous correction request found
  }

  // Determine current role
  const isRoberto = recentApprover == "Roberto Del Real";
  const isJose = recentApprover == "Jose Landeros";
  const isCoordinator = coordinators.includes(recentApprover);

  // Handle stay statuses (most common case)
  if (stayStatuses.includes(recentStatus)) {
    if (isRoberto) return "Roberto Del Real";
    if (isJose) return "Jose Landeros";
    if (isCoordinator) return "Coordinator";
  }

  // Handle rejections
  if (recentStatus == "Rejected") {
    if (isRoberto) return "Jose Landeros";
    if (isJose) return "Coordinator";
    if (isCoordinator) return context?.Form?.InvoicePage?.Contractor?.Text || "";
  }

  // Handle approvals
  if (recentStatus == "Approved") {
    if (isRoberto) return "Julie Blanco";
    if (isJose) return "Roberto Del Real";
    if (isCoordinator) return "Jose Landeros";
  }

  return "Pending Assignment";
};","ClearValueOnTrue":false,"ClearValueOnFalse":false,"Key":null,"Fields":[{"ModelKey":"Form.InvoicePage.Contractor","FieldName":"Contractor","IsSystemModelKey":false},{"ModelKey":"Form.InvoicePage.InvoiceNumber_Final","FieldName":"InvoiceNumber_Final","IsSystemModelKey":false},{"ModelKey":"Form.InvoicePage.InvoiceDetails","FieldName":"InvoiceDetails","IsSystemModelKey":false},{"ModelKey":"StatusFinal","FieldName":"StatusFinal","IsSystemModelKey":false},{"ModelKey":"StatusBy","FieldName":"StatusBy","IsSystemModelKey":false},{"ModelKey":"Form.InvoicePage.IssueDate_Final","FieldName":"IssueDate_Final","IsSystemModelKey":false}]}

