        return "Julie Blanco";
    }

    const grid = context?.Form?.InvoicePage?.DownPaymentReviewGrid || [];

    if (grid.length == 0) {
        return "Coordinator";
    }

    const mostRecentAction = grid[0];
    const recentApprover = mostRecentAction?.Reviewer_DownPayment?.Text || "";
    const recentStatus = mostRecentAction?.DownPaymentStatus?.Text || "";
    const stayStatuses = ["Received", "In Review"];

    const coordinatorLastNames = ["Cervantes", "Chavez", "Quintanilla", "Mendez", "Avila", "Becerra"];
    const isCoordinator = coordinatorLastNames.some(name => recentApprover.includes(name));

    const pmLastNames = ["Accardo", "Velores", "Landeros"];
    const isPM = pmLastNames.some(name => recentApprover.includes(name));

    // Pending Corrections - always goes to contractor
    if (recentStatus == "Pending Corrections") {
        return context?.Form?.InvoicePage?.Contractor?.Text || "MAROMA";
    }

    // Corrections Submitted - find who sent it for corrections
    if (recentStatus == "Corrections Submitted") {
        for (let i = 1; i < grid.length; i++) {
            if (grid[i]?.DownPaymentStatus?.Text == "Pending Corrections") {
                return grid[i]?.Reviewer_DownPayment?.Text || "Coordinator";
            }
        }
        return "Coordinator";
    }

    // Rejected - drop down one tier
    if (recentStatus == "Rejected") {
        if (isPM) return "Coordinator";
        if (isCoordinator) return context?.Form?.InvoicePage?.Contractor?.Text || "MAROMA";
        return "Coordinator";
    }

    // PM routing - approved goes to Julie
    if (isPM) {
        if (stayStatuses.includes(recentStatus)) return recentApprover;
        if (recentStatus == "Approved") return "Julie Blanco";
    }

    // Coordinator routing - approved escalates to PM
    if (isCoordinator) {
        if (stayStatuses.includes(recentStatus)) return recentApprover;
        if (recentStatus == "Approved") return "Program Manager";
    }

    // Contractor stay status - return to last internal reviewer
    if (stayStatuses.includes(recentStatus)) {
        return grid[0]?.Reviewer_DownPayment?.Text || "Coordinator";
    }

    return "MAROMA";
